import java.util.HashMap;
import java.util.Map;
import java.util.function.Supplier;
interface Document397 { void render(); }
class PdfDocument397 implements Document397 {
    public void render() { System.out.println("Pdf Document render"); }
}
class WordDocument397 implements Document397 {
    public void render() { System.out.println("Word Document render"); }
}
class DocumentRegistry397 {
    private final Map<String, Supplier<Document397>> registry = new HashMap<>();
    public DocumentRegistry397() {
        registry.put("pdf", PdfDocument397::new);
        registry.put("word", WordDocument397::new);
    }
    public Document397 create(String key) {
        Supplier<Document397> supplier = registry.get(key.toLowerCase());
        if (supplier == null) throw new IllegalArgumentException("Unknown: " + key);
        return supplier.get();
    }
}

